using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    // --- CalculateTotal: DataRow for simple inline cases ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Multiple items, 8% tax")]
    [DataRow(0.00, 5, 0.10, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.20, 0.00, DisplayName = "Zero quantity")]
    [DataRow(100.00, 1, 1.0, 200.00, DisplayName = "Max tax rate (100%)")]
    public void CalculateTotal_ValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- CalculateTotal: DynamicData with ValueTuples for invalid-input cases ---

    [TestMethod]
    [DynamicData(nameof(InvalidQuantityData))]
    public void CalculateTotal_NegativeQuantity_Throws(decimal unitPrice, int quantity, decimal taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));

        Assert.AreEqual("quantity", ex.ParamName);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate)> InvalidQuantityData =>
    [
        (10m, -1, 0.1m),
        (5m, -100, 0.0m),
    ];

    [TestMethod]
    [DynamicData(nameof(InvalidUnitPriceData))]
    public void CalculateTotal_NegativeUnitPrice_Throws(decimal unitPrice, int quantity, decimal taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));

        Assert.AreEqual("unitPrice", ex.ParamName);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate)> InvalidUnitPriceData =>
    [
        (-1m, 1, 0.1m),
        (-0.01m, 10, 0.0m),
    ];

    [TestMethod]
    [DataRow(-0.01)]
    [DataRow(1.01)]
    public void CalculateTotal_InvalidTaxRate_Throws(double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));

        Assert.AreEqual("taxRate", ex.ParamName);
    }

    // --- ApplyDiscount: DynamicData with ValueTuples ---

    [TestMethod]
    [DynamicData(nameof(DiscountData))]
    public void ApplyDiscount_ValidInputs_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> DiscountData =>
    [
        (100m, 0m, 100m),
        (100m, 10m, 90m),
        (100m, 50m, 50m),
        (100m, 100m, 0m),
        (200m, 25m, 150m),
        (0m, 50m, 0m),
    ];

    [TestMethod]
    [DataRow(-0.01)]
    [DataRow(100.01)]
    public void ApplyDiscount_InvalidPercent_Throws(double discountPercent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }

    // --- FormatPrice ---

    [TestMethod]
    [DataRow(19.99, "$", "$19.99", DisplayName = "Default symbol")]
    [DataRow(1234.5, "€", "€1234.50", DisplayName = "Euro symbol")]
    [DataRow(0.0, "$", "$0.00", DisplayName = "Zero price")]
    public void FormatPrice_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }
}

